const body = $input.first().json.body;
return [{ json: {
  imageUrl: body.image_url || '',
  campaignName: body.campaign_name || 'Untitled Campaign',
  productName: body.product_name || '',
  channels: body.channels || ['instagram_feed', 'facebook_ads', 'web_banner'],
  brandTemplate: body.brand_template || 'default',
  includeBleed: body.include_bleed || false,
  notifyChannel: body.notify_channel || '#design-assets',
  clientName: body.client_name || '',
  exportFormat: body.export_format || 'jpg',
  jpegQuality: body.jpeg_quality || 92
}}];

const metadata = JSON.parse($input.first().json.stdout || '{}');
const config = $('Validate & Parse Input').first().json;

const channelSpecs = {
  instagram_feed: [
    { name: 'Instagram Feed Square', width: 1080, height: 1080, aspect: '1:1', format: 'jpg', colorSpace: 'sRGB', maxSize: 30 },
    { name: 'Instagram Feed Portrait', width: 1080, height: 1350, aspect: '4:5', format: 'jpg', colorSpace: 'sRGB', maxSize: 30 }
  ],
  instagram_stories: [
    { name: 'Instagram Stories', width: 1080, height: 1920, aspect: '9:16', format: 'jpg', colorSpace: 'sRGB', maxSize: 30 }
  ],
  facebook_ads: [
    { name: 'Facebook Ad', width: 1200, height: 628, aspect: '1.91:1', format: 'jpg', colorSpace: 'sRGB', maxSize: 30 }
  ],
  web_banner: [
    { name: 'Web Hero Banner', width: 1920, height: 600, aspect: '3.2:1', format: 'jpg', colorSpace: 'sRGB', maxSize: 2 },
    { name: 'Web Leaderboard', width: 728, height: 90, aspect: '8:1', format: 'jpg', colorSpace: 'sRGB', maxSize: 1 }
  ],
  retail_pos: [
    { name: 'Retail A3 Portrait', width: 3508, height: 4961, aspect: '3:4', format: 'tiff', colorSpace: 'CMYK', maxSize: 200, bleed: 3 },
    { name: 'Retail A4 Portrait', width: 2480, height: 3508, aspect: '3:4', format: 'tiff', colorSpace: 'CMYK', maxSize: 150, bleed: 3 }
  ],
  email_header: [
    { name: 'Email Header', width: 600, height: 300, aspect: '2:1', format: 'jpg', colorSpace: 'sRGB', maxSize: 0.2 }
  ]
};

const variants = [];
config.channels.forEach(channel => {
  const specs = channelSpecs[channel] || [];
  specs.forEach(spec => {
    const slug = config.campaignName.replace(/\\s+/g, '-').toLowerCase();
    const product = config.productName.replace(/\\s+/g, '-').toLowerCase();
    variants.push({
      ...spec,
      channel,
      fileName: `${slug}_${product}_${channel}_${spec.width}x${spec.height}_v1.${spec.format}`,
      campaignName: config.campaignName,
      productName: config.productName,
      brandTemplate: config.brandTemplate,
      includeBleed: config.includeBleed && spec.bleed ? spec.bleed : 0,
      sourceWidth: metadata.width,
      sourceHeight: metadata.height
    });
  });
});

return variants.map(v => ({ json: v }));

const result = JSON.parse($input.first().json.stdout || '{}');
const variant = $('Generate Channel Variants').item;

return [{ json: {
  ...variant.json,
  exportStatus: result.status || 'error',
  exportPath: result.file || '',
  exportedAt: new Date().toISOString()
}}];

const allExports = $input.all().map(i => i.json);
const config = $('Validate & Parse Input').first().json;
const successful = allExports.filter(e => e.exportStatus === 'success');
const failed = allExports.filter(e => e.exportStatus !== 'success');

return [{ json: {
  campaignName: config.campaignName,
  productName: config.productName,
  totalExports: allExports.length,
  successCount: successful.length,
  failCount: failed.length,
  channels: [...new Set(allExports.map(e => e.channel))],
  exports: successful.map(e => ({
    name: e.name,
    fileName: e.fileName,
    size: e.width + 'x' + e.height,
    channel: e.channel
  })),
  failures: failed.map(e => e.name)
}}];

parameters.text:
:art: *Asset Pipeline Complete*

:camera: *{{ $json.campaignName }}* — {{ $json.productName }}
:white_check_mark: {{ $json.successCount }}/{{ $json.totalExports }} exports successful
:file_folder: Channels: {{ $json.channels.join(', ') }}

*Exports:*
{{ $json.exports.map(e => `• ${e.name}: ${e.fileName} (${e.size})`).join('\n') }}

{{ $json.failCount > 0 ? ':warning: *Failed:*\n' + $json.failures.map(f => '• ' + f).join('\n') : '' }}
